    11→// PVManager PersistentVolume 资源管理接口
    12→type PVManager interface {
    13→	// CreatePV 创建 PV
    14→	CreatePV(ctx context.Context, pv *corev1.PersistentVolume) error
    15→	// UpdatePV 更新 PV
    16→	UpdatePV(ctx context.Context, pv *corev1.PersistentVolume) error
    17→	// DeletePV 删除 PV
    18→	DeletePV(ctx context.Context, name string) error
    19→	// GetPV 获取 PV 信息
    20→	GetPV(ctx context.Context, name string) (*corev1.PersistentVolume, error)
    21→	// ListPVs 列出 PV
    22→	ListPVs(ctx context.Context) ([]*corev1.PersistentVolume, error)
    23→	// PVExists 检查 PV 是否存在
    24→	PVExists(ctx context.Context, name string) (bool, error)
    25→}
