    27→func (c *client) CreatePV(ctx context.Context, pv *corev1.PersistentVolume) error {
    28→	_, err := c.clientset.CoreV1().PersistentVolumes().Create(ctx, pv, metav1.CreateOptions{})
    29→	return err
    30→}
    31→
    32→func (c *client) UpdatePV(ctx context.Context, pv *corev1.PersistentVolume) error {
    33→	oldPV, err := c.clientset.CoreV1().PersistentVolumes().Get(ctx, pv.Name, metav1.GetOptions{})
    34→	if err != nil {
    35→		return err
    36→	}
    37→	pv.ResourceVersion = oldPV.ResourceVersion
    38→	_, err = c.clientset.CoreV1().PersistentVolumes().Update(ctx, pv, metav1.UpdateOptions{})
    39→	return err
    40→}
    41→
    42→func (c *client) DeletePV(ctx context.Context, name string) error {
    43→	return c.clientset.CoreV1().PersistentVolumes().Delete(ctx, name, metav1.DeleteOptions{})
    44→}
    45→
    46→func (c *client) GetPV(ctx context.Context, name string) (*corev1.PersistentVolume, error) {
    47→	return c.clientset.CoreV1().PersistentVolumes().Get(ctx, name, metav1.GetOptions{})
    48→}
    49→
    50→func (c *client) ListPVs(ctx context.Context) ([]*corev1.PersistentVolume, error) {
    51→	pvList, err := c.clientset.CoreV1().PersistentVolumes().List(ctx, metav1.ListOptions{})
    52→	if err != nil {
    53→		return nil, err
    54→	}
    55→
    56→	var pvs []*corev1.PersistentVolume
    57→	for i := range pvList.Items {
    58→		pvs = append(pvs, &pvList.Items[i])
    59→	}
    60→	return pvs, nil
    61→}
    62→
    63→func (c *client) PVExists(ctx context.Context, name string) (bool, error) {
    64→	_, err := c.clientset.CoreV1().PersistentVolumes().Get(ctx, name, metav1.GetOptions{})
    65→	if err != nil {
    66→		if k8serrors.IsNotFound(err) {
    67→			return false, nil
    68→		}
    69→		return false, err
    70→	}
    71→	return true, nil
    72→}
